values.value:
[
  {
    "name": "from_record",
    "label": "From Record",
    "description": "Read a file attached to the current record. Call with no arguments to auto-read the only file, or supply contentDocumentId to target a specific one.",
    "configFields": [
      {
        "name": "maxFileSizeKb",
        "type": "integer",
        "required": false,
        "help": "Maximum file size in kilobytes that this tool will attempt to decode. Files exceeding this limit return a structured failure. Default: 50 KB.",
        "label": "Max File Size (KB)",
        "placeholder": "50"
      },
      {
        "name": "allowedFileExtensions",
        "type": "array",
        "required": false,
        "help": "Optional restriction list. If set, only files whose extension matches an entry are processed; all others receive an unsupported-format failure. If omitted, all extensions are attempted.",
        "label": "Allowed File Extensions",
        "placeholder": "[\"csv\",\"txt\",\"json\"]"
      }
    ],
    "parameterFields": [],
    "configJsonSchema": {
      "$schema": "http://json-schema.org/draft-07/schema#",
      "type": "object",
      "properties": {
        "maxFileSizeKb": {
          "type": "integer",
          "description": "Maximum file size in kilobytes that this tool will attempt to decode. Files exceeding this limit return a structured failure. Default: 50 KB."
        },
        "allowedFileExtensions": {
          "type": "array",
          "description": "Optional restriction list. If set, only files whose extension matches an entry are processed; all others receive an unsupported-format failure. If omitted, all extensions are attempted.",
          "items": {
            "type": "string"
          }
        },
        "variant": {
          "type": "string",
          "enum": [
            "from_record"
          ]
        }
      }
    },
    "parametersJsonSchema": {
      "$schema": "http://json-schema.org/draft-07/schema#",
      "type": "object",
      "properties": {},
      "required": []
    }
  },
  {
    "name": "by_file_id",
    "label": "By File ID",
    "description": "Read a specific file using its Salesforce ContentDocument ID. Use when the file ID is already known (e.g. surfaced in the email attachment list).",
    "configFields": [
      {
        "name": "maxFileSizeKb",
        "type": "integer",
        "required": false,
